import React, { useEffect, useState } from 'react';
import classes from './About.module.css';
import Typography from '@material-ui/core/Typography';
import Avatar from '@material-ui/core/Avatar';
import Grid from '@material-ui/core/Grid';
import "react-responsive-carousel/lib/styles/carousel.min.css"; // requires a loader
import { Carousel } from 'react-responsive-carousel';
import AzureAuthFlow from '../../../assets/authFlow/AzureAuthFlow.gif';
import FacebookAuthFlow from '../../../assets/authFlow/FacebookAuthFlow.gif'
import GoogleAuthFlow from '../../../assets/authFlow/GoogleAuthFlow.gif'
import KeycloakAuthFlow from '../../../assets/authFlow/KeycloakAuthFlow.gif';
import Paper from '@material-ui/core/Paper';
import SocialMedia from '../../LeftPannel/SocialMedia/SocialMedia';


const About = () => {
    const time = new window.Date().getHours();

    const greetings = time < 10 ? "Good Morning" : time < 20 ? "Good Day" : "Good Evening";
    const [mediumData, getMediumData] = useState([]);
    const [gitHubData, getGitHubData] = useState([]);

    const getDataFromGetUrl = async (url) => {
        const response = await fetch(url);
        const json_data = await response.json();
        return json_data;
    }

    useEffect(() => {

        //medium API => https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@suryaprakash-pandey
        //Github API => https://api.github.com/users/surya5954/repos
        const medium_url = "https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@suryaprakash-pandey";
        const github_url = "https://api.github.com/users/surya5954/repos";

        getDataFromGetUrl(medium_url)
            .then((data) => {
                console.log(data);
                getMediumData(data.items);
                return getDataFromGetUrl(github_url);
            })
            .then((data) => {
                console.log(data);
                getGitHubData(data);
            })
    }, [])


    return (
        <div>
            <div className={classes.centerDiv}>
                <Typography variant="h6" component="h2" style={{ textAlign: "center" }}>
                    <h2>Hello there ! {greetings}</h2>
                </Typography>
                <hr></hr>
                <div className={classes.aboutBody}>
                    <Typography variant="h6" component="h2">
                        <h4> I am a Full-Stack JavaScript Developer with 6 years of work Experience.
                Reading, learning about new technologies was always in my hobby, Blogging about them is recently added.</h4>
                    </Typography>
                    <Typography variant="h6" component="h2">
                        <h4>Here are some of my blogs posted on Medium,</h4>
                    </Typography>
                </div>
                <Grid container style={{ justifyContent: 'center' }}>
                    <Grid item xs={10}>
                        <ul>
                            {mediumData.map((post) => (
                                <p key={post.pubDate} className={classes.post}>
                                    {/* <Avatar alt="HCL Connections" src={post.thumbnail} /> */}
                                    <a href={post.link} target="_blank" className={classes.postList}>{post.title}</a>

                                    {/* <img style={{ width: 200, height: 200 }} src={post.thumbnail} /> */}
                                    <span style={{ float: 'right' }}>Published On:  {new window.Date(post.pubDate).toLocaleDateString()}</span>
                                </p>
                            ))}
                        </ul>
                    </Grid>
                </Grid>
            </div>
            <Grid container className={classes.GitProjectTab}>
                <Grid item xs={10} sm={5}>
                    <div style={{ marginTop: '-30px' }}>
                        <Typography variant="h6" component="h4">
                            <h4>Securing your React SPA with Social Identity Providers like Microsoft, Google, Facebook etc.</h4>
                        </Typography>
                        <Typography variant="body2" component="p">
                            <b>Loginas: </b>
                            Open Source Project, <a className={classes.postList} href="https://github.com/surya5954/loginas.git">click here </a>
                             to view the Source code. Here are the commands to do local setup,
                        </Typography>

                        <Paper className={classes.codeSnippet}>
                            <Typography variant="body2" component="p">
                                git clone https://github.com/surya5954/loginas.git<br></br>
                                cd loginas <br></br>
                                npm install<br></br>
                                npm start<br></br>
                            </Typography>
                        </Paper>
                    </div>

                </Grid>
                <Grid item xs={10} sm={5}>
                    <Carousel>
                        <div>
                            <img src={AzureAuthFlow} />
                            <p className="legend">Azure Authorization Code flow with PCKE using React SPA</p>
                        </div>
                        <div>
                            <img src={FacebookAuthFlow} />
                            <p className="legend">Facebook Authorization Code flow with PCKE using React SPA</p>
                        </div>
                        <div>
                            <img src={GoogleAuthFlow} />
                            <p className="legend">Google Authorization Code flow with PCKE using React SPA</p>
                        </div>

                    </Carousel>
                </Grid>
            </Grid>
            <Grid container className={classes.GitProjectTab}>
                <Grid item xs={10} sm={5}>
                    {/* <Carousel > */}
                    <div>
                        <img src={KeycloakAuthFlow} style={{ width: '100%' }} />
                        {/* <p className="legend">Keycloak Authorization Code flow with PCKE using React SPA</p> */}
                    </div>
                    {/* </Carousel> */}

                </Grid>
                <Grid item xs={10} sm={5}>
                    <div style={{ marginTop: '-30px' }}>
                        <Typography variant="h6" component="h4">
                            <h4>Securing your React SPA with Keycloak (Use it as Identity or Service Provider)</h4>
                        </Typography>
                        <Typography variant="body2" component="p">
                            <b>Loginas: </b>
                            Open Source Project, <a className={classes.postList} href="https://github.com/surya5954/loginas.git">click here </a>
                             to view the Source code. Here are the commands to do local setup,
                        </Typography>

                        <Paper className={classes.codeSnippet}>
                            <Typography variant="body2" component="p">
                                git clone https://github.com/surya5954/loginas.git<br></br>
                                cd loginas <br></br>
                                npm install<br></br>
                                npm start<br></br>
                            </Typography>
                        </Paper>
                    </div>
                </Grid>
            </Grid>



            <div className={classes.mobileSocialMedia}>
                <hr></hr>
                <div className={classes.SocialMediaDiv}>
                    <SocialMedia />
                </div>

            </div>
        </div>
    )
}

export default About;
